class Solution:
    def findLatestTime(self, s: str) -> str:
        # Convert string to a list for easy manipulation
        time = list(s)

        # Replace '?' in hours (first two characters)
        if time[0] == '?':
            if time[1] == '?':
                # Both are unknown, set to maximum hour "11"
                time[0] = '1'
                time[1] = '1'
            elif int(time[1]) <= 1:
                # First hour digit is unknown, but second is <= 1, set to "1"
                time[0] = '1'
            else:
                # First hour digit is unknown, but second is > 1, set to "0"
                time[0] = '0'
        if time[1] == '?':
            if time[0] == '1':
                # Second hour digit is unknown, set to maximum "1"
                time[1] = '1'
            else:
                # Second hour digit is unknown, set to maximum "9"
                time[1] = '9'

        # Replace '?' in minutes (last two characters)
        if time[3] == '?':
            time[3] = '5'
        if time[4] == '?':
            time[4] = '9'

        # Join the list back to string and return
        return ''.join(time)
